import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { authAPI } from '../services/api';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  const fetchMe = useCallback(async () => {
    const token = localStorage.getItem('token');
    if (!token) { setLoading(false); return; }
    try {
      const { data } = await authAPI.me();
      setUser(data);
    } catch {
      localStorage.removeItem('token');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchMe(); }, [fetchMe]);

  const login = async (email, password) => {
  // 🔥 DEMO MODE (bypass backend)
  if (email === 'aurora@demo.com' && password === 'demo123') {
    const demoUser = {
      id: 1,
      username: 'aurora_styles',
      email: 'aurora@demo.com',
      bio: 'Minimalist fashion lover ✨',
      is_premium: true,
      profile_picture: null,
    };

    localStorage.setItem('token', 'demo-token');
    setUser(demoUser);

    return demoUser;
  }

  // ❌ real backend (still broken)
  const { data } = await authAPI.login({ email, password });
  localStorage.setItem('token', data.token);
  setUser(data.user);
  return data.user;
};

  const signup = async (username, email, password) => {
    const { data } = await authAPI.signup({ username, email, password });
    localStorage.setItem('token', data.token);
    setUser(data.user);
    return data.user;
  };

  const logout = () => {
    localStorage.removeItem('token');
    setUser(null);
  };

  const updateUser = (updated) => setUser((prev) => ({ ...prev, ...updated }));

  return (
    <AuthContext.Provider value={{ user, loading, login, signup, logout, updateUser, refreshUser: fetchMe }}>
      {children}
    </AuthContext.Provider>
  );
}

export const useAuth = () => {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used within AuthProvider');
  return ctx;
};
